    struct Model {
        int ch; int nlayers;
        const float* inpW; const float* inpB;
        const float* convW; const float* convB; const float* preluW;
        const float* outW; float outB;
    };

    inline const Model* Get(int eff) {
        static const Model radio = { 48, 11, TCN_RADIO_INPW, TCN_RADIO_INPB, TCN_RADIO_CONVW, TCN_RADIO_CONVB, TCN_RADIO_PRELU, TCN_RADIO_OUTW, -0.0001812083f };
        static const Model phone = { 48, 11, TCN_PHONE_INPW, TCN_PHONE_INPB, TCN_PHONE_CONVW, TCN_PHONE_CONVB, TCN_PHONE_PRELU, TCN_PHONE_OUTW, 0.01586364f };
        static const Model stormtrooper = { 48, 11, TCN_STORMTROOPER_INPW, TCN_STORMTROOPER_INPB, TCN_STORMTROOPER_CONVW, TCN_STORMTROOPER_CONVB, TCN_STORMTROOPER_PRELU, TCN_STORMTROOPER_OUTW, -0.0009867486f };
        static const Model combine = { 48, 11, TCN_COMBINE_INPW, TCN_COMBINE_INPB, TCN_COMBINE_CONVW, TCN_COMBINE_CONVB, TCN_COMBINE_PRELU, TCN_COMBINE_OUTW, -0.0006310833f };
        switch (eff) {
        case AudioEffects::EFF_RADIO: return &radio;
        case AudioEffects::EFF_PHONE: return &phone;
        case AudioEffects::EFF_STORMTROOPER: return &stormtrooper;
        case AudioEffects::EFF_COMBINE: return &combine;
        default: return nullptr;
        }
    }
